import {Readable} from 'node:stream';

app.get('/export.csv', async (req, res) => {
  res.setHeader('content-type', 'text/csv');
  res.setHeader('content-disposition', 'attachment; filename=export.csv');

  res.write('id,name,total\n');

  const client = await pool.connect();
  try {
    const cursor = client.query(new Cursor('SELECT id, name, total FROM orders ORDER BY id'));
    let rows;
    while ((rows = await cursor.read(1000)).length) {
      for (const r of rows) {
        res.write(`${r.id},${escape(r.name)},${r.total}\n`);
      }
      // wait for drain if needed
      if (res.writableNeedDrain) await new Promise(resolve => res.once('drain', resolve));
    }
    res.end();
  } finally {
    client.release();
  }
});

